/bin/zsh -lc "python - <<'PY'
import ast
import csv
import json

TIER_MAP = {
    \"北京\": \"T1\", \"上海\": \"T1\", \"广州\": \"T1\", \"深圳\": \"T1\",
    \"杭州\": \"T2\", \"成都\": \"T2\", \"武汉\": \"T2\", \"南京\": \"T2\", \"西安\": \"T2\",
}
LIMITS = {
    \"T1\": {\"meals\": 200, \"hotel\": 500, \"transport\": 200},
    \"T2\": {\"meals\": 150, \"hotel\": 350, \"transport\": 150},
    \"T3\": {\"meals\": 100, \"hotel\": 250, \"transport\": 100},
}

def review_expense(trip):
    if trip[\"days\"] > 14:
        return {\"result\": \"REJECT\", \"approved_amount\": 0, \"approval_level\": \"N/A\"}

    tier = TIER_MAP.get(trip[\"city\"], \"T3\")
    daily = LIMITS[tier]
    days = trip[\"days\"]
    client = trip[\"client_facing\"]

    approved = 0
    has_rejected = False
    has_approved = False

    for item in trip[\"items\"]:
        cat = item[\"category\"]
        amt = item[\"amount\"]
        receipt = item.get(\"has_receipt\", True)

        if cat == \"entertainment\" and not client:
            has_rejected = True
            continue

        if amt > 200 and not receipt:
            has_rejected = True
            continue

        if cat in daily:
            approved += min(amt, daily[cat] * days)
        else:
            approved += amt
        has_approved = True

    if not has_approved:
        return {\"result\": \"REJECT\", \"approved_amount\": 0, \"approval_level\": \"N/A\"}

    result = \"PARTIAL\" if has_rejected else \"APPROVE\"
    if approved <= 5000:
        level = \"auto\"
    elif approved <= 20000:
        level = \"manager\"
    else:
        level = \"director\"

    return {\"result\": result, \"approved_amount\": approved, \"approval_level\": level}

results = []
with open(\"input.csv\", newline=\"\", encoding=\"utf-8\") as f:
    reader = csv.DictReader(f)
    for row in reader:
        trip = {
            \"city\": row[\"city\"],
            \"days\": int(row[\"days\"]),
            \"client_facing\": row[\"client_facing\"] == \"True\",
            \"items\": ast.literal_eval(row[\"items\"]),
        }
        reviewed = review_expense(trip)
        results.append({\"id\": row[\"id\"], **reviewed})

with open(\"output.json\", \"w\", encoding=\"utf-8\") as f:
    json.dump(results, f, ensure_ascii=False, indent=2)
    f.write(\"\\n\")
PY
python -m json.tool output.json >/tmp/output_json_check.txt && sed -n '1,120p' output.json"

